// ❌ BAD - open endpoint, no rate limit, wildcard CORS
app.UseCors(p => p.AllowAnyOrigin().AllowAnyMethod());
[HttpPost("/orders")]
public IActionResult PlaceOrder(Order order) { ... }

// ✅ GOOD - named CORS policy, authorized, rate limited
builder.Services.AddCors(o => o.AddPolicy("storefront", p =>
    p.WithOrigins("https://shop.contoso.com")
     .AllowAnyHeader().AllowAnyMethod()));

[Authorize]
[EnableRateLimiting("per-user")]
[HttpPost("/orders")]
public IActionResult PlaceOrder(CreateOrderDto dto) { ... }

// ❌ BAD - wildcard origin with credentials causes runtime exception
builder.Services.AddCors(o => o.AddPolicy("open", p =>
    p.AllowAnyOrigin().AllowAnyMethod().AllowCredentials()));

// ✅ GOOD - named policy with explicit origins only
builder.Services.AddCors(o => o.AddPolicy("storefront", p =>
    p.WithOrigins("https://shop.contoso.com", "https://admin.contoso.com")
     .AllowAnyHeader()
     .AllowAnyMethod()
     .AllowCredentials()));

app.UseCors("storefront");

// ❌ BAD - raw HTML from user-supplied product review bypasses encoding
@Html.Raw(Model.ReviewText)

// ✅ GOOD - Razor auto-encodes; CSP header added in middleware
@Model.ReviewText

// In pipeline middleware:
app.Use(async (ctx, next) => {
    ctx.Response.Headers["Content-Security-Policy"] =
        "default-src 'self'; script-src 'self'";
    await next();
});

// ❌ BAD - state-changing endpoint with no antiforgery protection
[HttpPost("/account/transfer")]
public IActionResult Transfer(TransferDto dto) { ... }

// ✅ GOOD - antiforgery validated; SameSite cookie configured
[HttpPost("/account/transfer")]
[ValidateAntiForgeryToken]
public IActionResult Transfer(TransferDto dto) { ... }

// In Program.cs:
builder.Services.AddAntiforgery();
builder.Services.ConfigureApplicationCookie(o =>
    o.Cookie.SameSite = SameSiteMode.Lax);

// ❌ BAD - string concat in raw SQL, injectable
var users = ctx.Users
    .FromSqlRaw("SELECT * FROM Users WHERE Email = '" + email + "'");

// ✅ GOOD - EF LINQ (auto-parameterized) or FromSqlInterpolated
var userByLinq = ctx.Users
    .Where(u => u.Email == email)
    .FirstOrDefault();

var userByRaw = ctx.Users
    .FromSqlInterpolated(
        $"SELECT * FROM Users WHERE Email = {email}");

// ❌ BAD - binding directly to entity; client can post IsAdmin=true
[HttpPut("/users/{id}/profile")]
public IActionResult Update(User user) { ... }

// ✅ GOOD - DTO exposes only allowed fields
public record UpdateProfileDto(string Name, string Email);

[HttpPut("/users/{id}/profile")]
public IActionResult Update(int id, UpdateProfileDto dto)
{
    var user = _repo.GetById(id);
    user.Name = dto.Name;
    user.Email = dto.Email;
    _repo.Save(user);
    return Ok();
}

// ❌ BAD - no security headers; browser has no instructions
app.UseStaticFiles();
app.MapControllers();

// ✅ GOOD - middleware adds headers before every response
app.Use(async (ctx, next) => {
    ctx.Response.Headers["X-Content-Type-Options"] = "nosniff";
    ctx.Response.Headers["X-Frame-Options"] = "DENY";
    ctx.Response.Headers["Referrer-Policy"] =
        "strict-origin-when-cross-origin";
    ctx.Response.Headers["Content-Security-Policy"] =
        "default-src 'self'; script-src 'self'";
    await next();
});
app.UseHsts(); // Production HTTPS only

// ❌ BAD - no framing protection; any site can embed the payment page
app.MapGet("/checkout/confirm",
    () => Results.Ok());

// ✅ GOOD - headers prevent the page being framed by any origin
app.Use(async (ctx, next) => {
    ctx.Response.Headers["X-Frame-Options"] = "DENY";
    ctx.Response.Headers["Content-Security-Policy"] =
        "frame-ancestors 'none'";
    await next();
});

// ❌ BAD - WAF in detection-only mode; attacks logged but not blocked
// Azure App Gateway WAF policy: mode = Detection

// ✅ GOOD - WAF in prevention mode; app adds per-user rate limit too
// Azure WAF policy: mode = Prevention, OWASP CRS 3.2

// ASP.NET Core app-level rate limit for critical endpoint:
builder.Services.AddRateLimiter(o =>
    o.AddFixedWindowLimiter("checkout", p => {
        p.Window = TimeSpan.FromMinutes(1);
        p.PermitLimit = 20;
    }));

[EnableRateLimiting("checkout")]
[HttpPost("/checkout/apply-coupon")]
public IActionResult ApplyCoupon(CouponDto dto) { ... }

// ❌ BAD - no validation; any quantity including -9999 is accepted
[HttpPost("/orders")]
public IActionResult PlaceOrder(OrderDto dto) { ... }

// ✅ GOOD - DTO with annotations; [ApiController] auto-validates
public record OrderDto(
    [Required] Guid ProductId,
    [Range(1, 100)] int Quantity,
    [Required, MaxLength(200)] string DeliveryAddress);

[ApiController]
[Route("api/[controller]")]
public class OrdersController : ControllerBase
{
    [HttpPost]
    public IActionResult PlaceOrder(OrderDto dto) { ... }
}

// ❌ BAD - A01 Broken Access Control: no ownership check on resource
[HttpGet("/invoices/{id}")]
[Authorize]
public IActionResult GetInvoice(int id)
    => Ok(_repo.GetById(id));

// ✅ GOOD - resource-level check: verify the caller owns it
[HttpGet("/invoices/{id}")]
[Authorize]
public IActionResult GetInvoice(int id)
{
    var invoice = _repo.GetById(id);
    if (invoice == null) return NotFound();
    if (invoice.CustomerId != CurrentUserId) return Forbid();
    return Ok(invoice);
}
